function linha(entry, isUser) {
  if (!entry) return null;
  const medalha = entry.posicao === 1 ? '🥇' : entry.posicao === 2 ? '🥈' : entry.posicao === 3 ? '🥉' : '  ';
  const pts = fmtPts(entry.pontos);
  const liga = entry.liga ? ' (' + entry.liga + ')' : '';
  if (isUser) {
    return '👉 *_#' + entry.posicao + ' Você_* — ' + pts + ' pts' + liga;
  }
  return (medalha ? medalha + ' ' : '') + '#' + entry.posicao + ' ' + entry.apelido + ' — ' + pts + ' pts' + liga;
}

const isInTop3 = posicao <= 3;

const top3Lines = [r.primeiro, r.segundo, r.terceiro]
  .filter(Boolean)
  .map(e => linha(e, e.posicao === posicao));

const vizinhanca = [];
if (!isInTop3) {
  if (r.dois_a_frente) vizinhanca.push(linha(r.dois_a_frente, false));
  if (r.um_a_frente) vizinhanca.push(linha(r.um_a_frente, false));
  vizinhanca.push(linha(r.usuario, true));
  if (r.um_a_tras) vizinhanca.push(linha(r.um_a_tras, false));
  if (r.dois_a_tras) vizinhanca.push(linha(r.dois_a_tras, false));
}

let msg = '🏆 *_Ranking Global_*\n\n';
msg += '*_Líderes:_*\n' + top3Lines.join('\n');

if (!isInTop3) {
  msg += '\n\n*_📍 Sua posição:_*\n' + vizinhanca.join('\n');
}

msg += '\n\n*_Total de participantes:_* ' + total;

return [{ json: { output: msg } }];

const waData = $('Extrair Dados WA').first().json;
const phone = waData.phone;
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
const session = sessions['wa_' + phone] || {};
const tokens = session.tokens || [];
const apelido = session.apelido || 'você';

function brl(v) {
  const parts = parseFloat(v || 0).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function num8(v) {
  const n = v * 1;
  const str = n.toFixed(8);
  const dot = str.indexOf('.');
  const intPart = str.slice(0, dot);
  const decPart = str.slice(dot + 1);
  return intPart.replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ',' + decPart;
}

function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return String(d); }
}

function fmtQty(n) {
  return n.toLocaleString('pt-BR');
}

if (!tokens || tokens.length === 0) {
  return [{ json: { output: 'Você ainda não tem nenhum Pin. 📌\n\nQuer saber mais sobre o seu Objetivo? Me manda *_objetivo_*' } }];
}

const totalInvestido = tokens.reduce(function(acc, t) { return acc + (t.valor_token * t.quantidade_tokens); }, 0);
const rendDiarioTotal = tokens.reduce(function(acc, t) { return acc + t.rendimento_token; }, 0);
const numPins = tokens.length;

// Agrupar por risco
const byRisk = {};
for (const t of tokens) {
  const r = t.risco || 'N/A';
  if (!byRisk[r]) byRisk[r] = { pins: 0, investido: 0, rendDiario: 0 };
  byRisk[r].pins++;
  byRisk[r].investido += t.valor_token * t.quantidade_tokens;
  byRisk[r].rendDiario += t.rendimento_token;
}

let msg = '*_📌 Seus Pins_*\n\n';
msg += 'Olá, ' + apelido + '! Aqui está um resumo dos seus Pins:\n\n';

msg += '*_📋 Visão Geral_*\n\n';
msg += '💰 Patrimônio em Pins: ' + brl(totalInvestido) + '\n';
msg += '🎯 Pins diferentes: ' + numPins + '\n';
msg += '📈 Rendimento diário total: R$ ' + num8(rendDiarioTotal) + '\n\n';

msg += '*_🔐 Por Nível de Risco_*\n\n';
for (const [risco, data] of Object.entries(byRisk)) {
  msg += '💰 *_Risco ' + risco + '_*\n';
  msg += 'Pins: ' + data.pins + '\n';
  msg += 'Alocado: ' + brl(data.investido) + '\n';
  msg += 'Rendimento diário: R$ ' + num8(data.rendDiario) + '\n\n';
}

msg += '*_📌 Detalhe dos Pins_*\n\n';
for (const t of tokens) {
  const invest = t.valor_token * t.quantidade_tokens;
  const rend = t.rendimento_token;
  msg += '📌 *_' + (t.razao_social || 'Pin ' + t.token_id) + '_*\n';
  msg += 'Risco: ' + (t.risco || 'N/A') + '\n';
  msg += 'Quantidade: ' + fmtQty(t.quantidade_tokens) + ' tokens\n';
  msg += 'Valor por token: ' + brl(t.valor_token) + '\n';
  msg += 'Total em Pins: ' + brl(invest) + '\n';
  msg += 'Rendimento diário: R$ ' + num8(rend) + '\n';
  msg += 'Vencimento: ' + fmtDate(t.vencimento) + '\n\n';
}

msg += 'Quer saber mais sobre o seu Objetivo? Me manda *_objetivo_*';

return [{ json: { output: msg } }];
